const ticker = String($input.first().json.ticker || '')
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error('Ticker is missing');
}

const companies = {
  AAPL: {
    companyName: 'Apple',
    aliases: ['Apple', 'Apple Inc', 'Apple Inc.', 'AAPL']
  },
  TSLA: {
    companyName: 'Tesla',
    aliases: ['Tesla', 'Tesla Inc', 'Tesla Inc.', 'TSLA']
  },
  NVDA: {
    companyName: 'NVIDIA',
    aliases: ['NVIDIA', 'Nvidia', 'NVIDIA Corporation', 'NVDA']
  },
  MSFT: {
    companyName: 'Microsoft',
    aliases: ['Microsoft', 'Microsoft Corporation', 'MSFT']
  },
  AMZN: {
    companyName: 'Amazon',
    aliases: ['Amazon', 'Amazon.com', 'Amazon.com Inc.', 'AMZN']
  },
  GOOGL: {
    companyName: 'Alphabet',
    aliases: ['Google', 'Alphabet', 'Alphabet Inc.', 'GOOGL']
  },
  META: {
    companyName: 'Meta',
    aliases: ['Meta', 'Meta Platforms', 'Facebook', 'META']
  }
};

const company = companies[ticker] || {
  companyName: ticker,
  aliases: [ticker]
};

return [
  {
    json: {
      ticker,
      companyName: company.companyName,
      aliases: company.aliases
    }
  }
];

const article = $json;

// פרטי החברה שהתקבלו מהצומת Prepare Company Search
const companyData =
  $('Prepare Company Search').first().json;

const ticker = String(
  companyData.ticker || ''
)
  .trim()
  .toUpperCase();

const companyName = String(
  companyData.companyName || ticker
).trim();

const aliases = Array.isArray(companyData.aliases)
  ? companyData.aliases
  : [companyName, ticker];

// טקסטים מתוך הכתבה
const title = String(article.title || '').trim();
const description = String(
  article.description || ''
).trim();
const snippet = String(article.snippet || '').trim();

const titleLower = title.toLowerCase();
const descriptionLower = description.toLowerCase();
const snippetLower = snippet.toLowerCase();

// רשימת מונחי החיפוש של החברה
const searchTerms = [
  ticker,
  companyName,
  ...aliases
]
  .map(term => String(term).trim().toLowerCase())
  .filter(Boolean);

// מסירים כפילויות
const uniqueSearchTerms = [
  ...new Set(searchTerms)
];

// בדיקה האם אחד משמות החברה מופיע בטקסט
function containsCompany(text) {
  return uniqueSearchTerms.some(term =>
    text.includes(term)
  );
}

const companyInTitle =
  containsCompany(titleLower);

const companyInDescription =
  containsCompany(descriptionLower);

const companyInSnippet =
  containsCompany(snippetLower);

// מציאת הישות שמתאימה לטיקר המבוקש
const entities = Array.isArray(article.entities)
  ? article.entities
  : [];

const matchingEntity = entities.find(entity =>
  String(entity.symbol || '')
    .trim()
    .toUpperCase() === ticker
);

const matchScore = Number(
  matchingEntity?.match_score || 0
);

const sentimentScore =
  matchingEntity?.sentiment_score ?? null;

// חישוב ציון רלוונטיות פנימי
let relevancePoints = 0;

if (companyInTitle) {
  relevancePoints += 3;
}

if (companyInDescription) {
  relevancePoints += 2;
}

if (companyInSnippet) {
  relevancePoints += 1;
}

if (matchScore >= 15) {
  relevancePoints += 2;
} else if (matchScore >= 10) {
  relevancePoints += 1;
}

// כתבה תעבור אם היא באמת עוסקת בחברה,
// ולא רק מזכירה אותה באופן צדדי.
const isRelevant =
  companyInTitle ||
  companyInDescription ||
  (companyInSnippet && matchScore >= 10) ||
  matchScore >= 15;

if (!isRelevant) {
  return null;
}

return {
  json: {
    uuid: String(article.uuid || ''),

    ticker,
    companyName,

    title,

    summary:
      description ||
      snippet ||
      '',

    description,
    snippet,

    link: String(article.url || ''),

    published: String(
      article.published_at || ''
    ),

    source: String(
      article.source || 'Marketaux'
    ),

    news_provider: 'Marketaux',

    match_score: matchScore,
    sentiment_score: sentimentScore,

    relevance_points: relevancePoints,

    relevance_reasons: {
      company_in_title: companyInTitle,
      company_in_description:
        companyInDescription,
      company_in_snippet: companyInSnippet,
      marketaux_match_score: matchScore
    }
  }
};

const items = $input.all();

const companyData =
  $('Prepare Company Search').first().json;

const ticker = String(companyData.ticker || '')
  .trim()
  .toUpperCase();

const companyName = String(
  companyData.companyName || ticker
).trim();

const aliases = Array.isArray(companyData.aliases)
  ? companyData.aliases
  : [companyName, ticker];

// בניית שמות אפשריים של החברה
const searchTerms = [
  ticker,
  companyName,
  ...aliases
]
  .map(value => String(value).trim().toLowerCase())
  .filter(Boolean);

const uniqueTerms = [...new Set(searchTerms)];

function containsCompany(text) {
  const normalizedText = String(text || '').toLowerCase();

  return uniqueTerms.some(term =>
    normalizedText.includes(term)
  );
}

// נרמול כותרת לצורך זיהוי כפילויות
function normalizeHeadline(text) {
  return String(text || '')
    .toLowerCase()
    .replace(/&[^;]+;/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const candidates = [];

for (const item of items) {
  const article = item.json;

  const title = String(
    article.headline || ''
  ).trim();

  const summary = String(
    article.summary || ''
  ).trim();

  const link = String(
    article.url || ''
  ).trim();

  if (!title || !link) {
    continue;
  }

  const companyInTitle =
    containsCompany(title);

  const companyInSummary =
    containsCompany(summary);

  const relatedTickers = String(
    article.related || ''
  )
    .split(',')
    .map(value => value.trim().toUpperCase())
    .filter(Boolean);

  const tickerInRelated =
    relatedTickers.includes(ticker);

  /*
   * related לבדו אינו מספיק,
   * כי Finnhub סימן גם כתבות על SpaceX כ-MSFT.
   */
  let relevanceScore = 0;

  if (companyInTitle) {
    relevanceScore += 5;
  }

  if (companyInSummary) {
    relevanceScore += 2;
  }

  if (tickerInRelated) {
    relevanceScore += 1;
  }

  /*
   * תנאי מעבר:
   * החברה חייבת להופיע בכותרת,
   * או להופיע בתקציר יחד עם related מתאים.
   */
  const isRelevant =
    companyInTitle ||
    (companyInSummary && tickerInRelated);

  if (!isRelevant) {
    continue;
  }

  const timestamp = Number(
    article.datetime || 0
  );

  let published = '';

  if (timestamp > 0) {
    published =
      new Date(timestamp * 1000).toISOString();
  }

  candidates.push({
    id: String(article.id || ''),
    ticker,
    companyName,

    title,
    summary,

    link,
    published,

    source: String(
      article.source || 'Finnhub'
    ),

    news_provider: 'Finnhub',

    relevance_score: relevanceScore,

    relevance_reasons: {
      company_in_title: companyInTitle,
      company_in_summary: companyInSummary,
      ticker_in_related: tickerInRelated
    },

    original_datetime: timestamp,
    normalized_headline:
      normalizeHeadline(title)
  });
}

// מיון קודם לפי רלוונטיות,
// ואחר כך לפי תאריך חדש יותר
candidates.sort((a, b) => {
  if (b.relevance_score !== a.relevance_score) {
    return b.relevance_score - a.relevance_score;
  }

  return (
    b.original_datetime -
    a.original_datetime
  );
});

// הסרת כפילויות
const seenUrls = new Set();
const seenTitles = new Set();
const uniqueArticles = [];

for (const article of candidates) {
  const urlKey = article.link.toLowerCase();
  const titleKey = article.normalized_headline;

  if (
    seenUrls.has(urlKey) ||
    seenTitles.has(titleKey)
  ) {
    continue;
  }

  seenUrls.add(urlKey);
  seenTitles.add(titleKey);

  uniqueArticles.push(article);
}

// עד 7 כתבות מ-Finnhub
const selected = uniqueArticles.slice(0, 7);

return selected.map(article => {
  const {
    original_datetime,
    normalized_headline,
    ...output
  } = article;

  return {
    json: output
  };
});

const inputItems = $input.all();

// נרמול כותרת לצורך השוואה בין המקורות
function normalizeTitle(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/&[^;]+;/g, ' ')
    .replace(/\bcorporation\b/g, ' ')
    .replace(/\bcorp\b/g, ' ')
    .replace(/\binc\b/g, ' ')
    .replace(/\bmsft\b/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// יצירת רשימת מילים משמעותיות מהכותרת
function getTitleWords(value) {
  const ignoredWords = new Set([
    'the',
    'a',
    'an',
    'and',
    'or',
    'of',
    'to',
    'for',
    'in',
    'on',
    'at',
    'as',
    'is',
    'are',
    'was',
    'with',
    'from',
    'by',
    'this',
    'that'
  ]);

  return normalizeTitle(value)
    .split(' ')
    .filter(word =>
      word.length > 2 &&
      !ignoredWords.has(word)
    );
}

// בדיקת דמיון בין שתי כותרות
function titleSimilarity(firstTitle, secondTitle) {
  const firstWords = new Set(
    getTitleWords(firstTitle)
  );

  const secondWords = new Set(
    getTitleWords(secondTitle)
  );

  if (
    firstWords.size === 0 ||
    secondWords.size === 0
  ) {
    return 0;
  }

  let commonWords = 0;

  for (const word of firstWords) {
    if (secondWords.has(word)) {
      commonWords++;
    }
  }

  return commonWords /
    Math.min(firstWords.size, secondWords.size);
}

// עדיפות לפריט בעל מידע עשיר יותר
function articleQuality(article) {
  let score = 0;

  if (article.title) {
    score += 2;
  }

  if (article.summary) {
    score += Math.min(
      String(article.summary).length / 200,
      3
    );
  }

  if (article.link) {
    score += 1;
  }

  if (article.published) {
    score += 1;
  }

  if (article.news_provider === 'Marketaux') {
    score += 0.5;
  }

  return score;
}

const articles = inputItems
  .map(item => item.json)
  .filter(article =>
    article.title &&
    article.link
  );

// ממיינים תחילה לפי תאריך, החדש ביותר ראשון
articles.sort((a, b) => {
  const firstDate =
    new Date(a.published || 0).getTime();

  const secondDate =
    new Date(b.published || 0).getTime();

  return secondDate - firstDate;
});

const selectedArticles = [];

for (const article of articles) {
  const normalizedCurrentTitle =
    normalizeTitle(article.title);

  let duplicateIndex = -1;

  for (
    let index = 0;
    index < selectedArticles.length;
    index++
  ) {
    const existing =
      selectedArticles[index];

    const sameUrl =
      String(existing.link || '')
        .toLowerCase() ===
      String(article.link || '')
        .toLowerCase();

    const exactSameTitle =
      normalizeTitle(existing.title) ===
      normalizedCurrentTitle;

    const similarTitle =
      titleSimilarity(
        existing.title,
        article.title
      ) >= 0.8;

    if (
      sameUrl ||
      exactSameTitle ||
      similarTitle
    ) {
      duplicateIndex = index;
      break;
    }
  }

  // לא נמצאה כפילות
  if (duplicateIndex === -1) {
    selectedArticles.push(article);
    continue;
  }

  // נמצאה כפילות:
  // נשמור את הגרסה בעלת המידע העשיר יותר
  const existingArticle =
    selectedArticles[duplicateIndex];

  if (
    articleQuality(article) >
    articleQuality(existingArticle)
  ) {
    selectedArticles[duplicateIndex] =
      article;
  }
}

// מיון מחדש לפי תאריך
selectedArticles.sort((a, b) => {
  const firstDate =
    new Date(a.published || 0).getTime();

  const secondDate =
    new Date(b.published || 0).getTime();

  return secondDate - firstDate;
});

// עד 10 כתבות בסך הכול
return selectedArticles
  .slice(0, 10)
  .map(article => ({
    json: article
  }));

const items = $input.all();

const articles = items
  .map(item => item.json)
  .filter(article =>
    article.title &&
    article.link
  );

const triggerInput =
  $('When Executed by Another Workflow')
    .first()
    .json;

const ticker = String(
  articles[0]?.ticker ??
  triggerInput.ticker ??
  ''
)
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error(
    'Ticker is missing in Build News Payload'
  );
}

const companyName = String(
  articles[0]?.companyName ??
  ticker
).trim();

return [
  {
    json: {
      ticker,
      company_name: companyName,
      article_count: articles.length,
      news_articles: articles
    }
  }
];
